SELECT COUNT(spec_id) AS design_count
FROM design_specifications
WHERE size_id = 0;

SELECT design_details, material, color
FROM design_specifications
WHERE size_id = 0;

SELECT SUM(sold_units) AS total_sold_units
FROM size_distribution
WHERE size_id = 1 AND region = 'North America';

SELECT size_id, SUM(sold_units) AS total_units_sold
FROM size_distribution
GROUP BY size_id;
